"""Одиночный прямоугольный импульс."""from __future__ import annotationsimport numpy as npfrom .base import BaseSignal, _time_axis_GEOM_EPS = 1.0e-12class PulseSignal(BaseSignal):    name = "Прямоугольный импульс"    description = ("Одиночный прямоугольный импульс. Должен полностью "                   "помещаться в [0, duration].")    params_schema = {        "amplitude": {"type": "float", "default": 1.0, "min": 0.0, "max": 1.0e6,                      "label": "Амплитуда", "units": "В"},        "width":     {"type": "float", "default": 0.1, "min": 1.0e-6, "max": 3600.0,                      "label": "Ширина импульса", "units": "с"},        "center":    {"type": "float", "default": 0.5, "min": 0.0, "max": 3600.0,                      "label": "Положение центра", "units": "с"},        "duration":  {"type": "float", "default": 1.0, "min": 1.0e-6, "max": 3600.0,                      "label": "Длительность", "units": "с"},        "fs":        {"type": "float", "default": 1000.0, "min": 1.0, "max": 1.0e6,                      "label": "Частота дискретизации", "units": "Гц"},    }    def _compute(self, p: dict) -> tuple[np.ndarray, np.ndarray]:        width, center, duration = p["width"], p["center"], p["duration"]        if width > duration + _GEOM_EPS:            raise ValueError(f"width={width} с превышает duration={duration} с")        if not (-_GEOM_EPS <= center <= duration + _GEOM_EPS):            raise ValueError(                f"center={center} с вне интервала [0, duration={duration}]"            )        start = center - 0.5 * width        end = center + 0.5 * width        if start < -_GEOM_EPS:            raise ValueError(                f"импульс начинается в t={start:.6f} с < 0 "                f"(center={center}, width={width})"            )        if end > duration + _GEOM_EPS:            raise ValueError(                f"импульс заканчивается в t={end:.6f} с > duration={duration} "                f"(center={center}, width={width})"            )        t = _time_axis(duration, p["fs"])        x = np.zeros_like(t)        mask = (t >= start) & (t <= end)        x[mask] = p["amplitude"]        return t, x